Regret-based insertion with spatial proximity tie-breaking and forced fallback using earliest compatible existing assign index}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for shipIdx := 0; shipIdx < len(oris); shipIdx++ {
		ori := oris[shipIdx]
		des := dess[shipIdx]
		shipID := total_ship + shipIdx

		bestAssignIdx := -1
		bestScore := 1e18

		existingCount := dispatch.AssignsLen
		for i := 0; i < existingCount; i++ {
			assign := &dispatch.Assigns[i]
			savedCost := assign.Cost
			ok := assign.AddShip(shipID, ori, des)
			if !ok {
				continue
			}
			assign.GenRoute()
			newCost := assign.Cost
			if newCost < 0 || newCost < savedCost-1e9 {
				assign.RemoveShip(shipID)
				assign.GenRoute()
				continue
			}
			costDelta := newCost - savedCost
			proximity := cal_dis(assign.StationCurrent, ori)
			score := costDelta*0.8 + proximity*0.2
			if score < bestScore {
				bestScore = score
				bestAssignIdx = i
			}
			assign.RemoveShip(shipID)
			assign.GenRoute()
		}

		inserted := false
		if bestAssignIdx != -1 {
			success := dispatch.Assigns[bestAssignIdx].AddShip(shipID, ori, des)
			if success {
				dispatch.Assigns[bestAssignIdx].GenRoute()
				inserted = true
			}
		}

		if !inserted {
			fallbackIdx := -1
			for i := 0; i < MAXASSIGNS; i++ {
				var testAssign Assign
				ok := testAssign.AddShip(shipID, ori, des)
				if ok && i >= existingCount {
					testAssign.GenRoute()
					if testAssign.Cost >= 0 {
						fallbackIdx = i
						break
					}
				}
				if ok && i < existingCount {
					dispatch.Assigns[i].RemoveShip(shipID)
					dispatch.Assigns[i].GenRoute()
				}
			}
			if fallbackIdx == -1 {
				for i := 0; i < MAXASSIGNS; i++ {
					var testAssign Assign
					ok := testAssign.AddShip(shipID, ori, des)
					if ok {
						testAssign.GenRoute()
						if testAssign.Cost >= 0 {
							fallbackIdx = i
							break
						}
					}
				}
			}
			if fallbackIdx != -1 {
				if fallbackIdx < existingCount {
					success := dispatch.Assigns[fallbackIdx].AddShip(shipID, ori, des)
					if success {
						dispatch.Assigns[fallbackIdx].GenRoute()
						inserted = true
					}
				} else {
					idx := fallbackIdx
					success := dispatch.Assigns[idx].AddShip(shipID, ori, des)
					if success {
						dispatch.Assigns[idx].GenRoute()
						if idx >= dispatch.AssignsLen {
							dispatch.AssignsLen = idx + 1
						}
						inserted = true
					}
				}
			}
		}

		if !inserted {
			for i := 0; i < MAXASSIGNS; i++ {
				var testAssign Assign
				ok := testAssign.AddShip(shipID, ori, des)
				if ok {
					testAssign.GenRoute()
					if testAssign.Cost >= 0 {
						success := dispatch.Assigns[i].AddShip(shipID, ori, des)
						if success {
							dispatch.Assigns[i].GenRoute()
							if i >= dispatch.AssignsLen {
								dispatch.AssignsLen = i + 1
							}
							inserted = true
							break
						}
					}
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

